const payload = $input.first().json.body ?? $input.first().json;
const metadata = (payload.metadata && typeof payload.metadata === 'object') ? payload.metadata : {};
const platforms = Array.isArray(metadata.platforms) ? metadata.platforms.map((p) => String(p).toLowerCase()) : ['youtube'];
const jobId = payload.jobId;
const forceImmediateUpload = Boolean(metadata.forceImmediateUpload);

const scheduleRaw = String(payload.scheduledTime || '').trim();
const scheduleFromPayload = forceImmediateUpload ? '' : String(payload.scheduledUploadAt || scheduleRaw).trim();
const parseScheduleIso = (input) => {
  const value = String(input || '').trim();
  if (!value) return '';

  let d = null;
  if (/^\d{2}:\d{2}$/.test(value)) {
    const [hh, mm] = value.split(':').map(Number);
    d = new Date();
    d.setHours(hh, mm, 0, 0);
    if (d.getTime() <= Date.now() + 30000) d.setDate(d.getDate() + 1);
  } else if (/^\d{4}-\d{2}-\d{2}\s+\d{2}:\d{2}$/.test(value)) {
    d = new Date(value.replace(' ', 'T') + ':00');
  } else {
    d = new Date(value);
  }

  if (!(d instanceof Date) || Number.isNaN(d.getTime())) return '';
  return d.toISOString();
};

const scheduledUploadAtIso = forceImmediateUpload ? '' : parseScheduleIso(scheduleFromPayload);
const normalizedScheduledTime = (() => {
  if (forceImmediateUpload) return 'Langsung upload';
  if (!scheduledUploadAtIso) return scheduleRaw;
  const d = new Date(scheduledUploadAtIso);
  const pad = (num) => String(num).padStart(2, '0');
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}`;
})();

if (!jobId) throw new Error('[VidGen] jobId wajib ada di payload');
if (!payload.prompt) throw new Error('[VidGen] field prompt wajib ada di payload');

const toInt = (value, fallback) => {
  const parsed = parseInt(value, 10);
  return Number.isFinite(parsed) ? parsed : fallback;
};

const stableSeedFromString = (input) => {
  let h = 2166136261;
  const text = String(input || '');
  for (let i = 0; i < text.length; i += 1) {
    h ^= text.charCodeAt(i);
    h += (h << 1) + (h << 4) + (h << 7) + (h << 8) + (h << 24);
  }
  return Math.abs(h >>> 0) % 2147483000;
};

const seriesId = String(metadata.seriesId || payload.seriesId || payload.uid || jobId);
const episodeNumber = toInt(metadata.episodeNumber ?? metadata.part, 1);
const characterName = String(metadata.characterName || metadata.character?.name || '').trim();
const characterAnchorRaw = String(metadata.characterAnchor || metadata.characterDescription || '').trim();
const characterRefImageUrl = String(metadata.characterRefImageUrl || metadata.characterRefImage || '').trim();
const requestedSeed = toInt(metadata.characterSeed ?? metadata.seed, -1);
const characterSeed = requestedSeed >= 0
  ? requestedSeed
  : stableSeedFromString(`${seriesId}|${characterName}|${characterAnchorRaw || payload.title}`);
const defaultAnchor = characterName
  ? `${characterName}, same face identity, same age range, same hairstyle, same skin tone, same facial structure`
  : 'one recurring protagonist with identical face identity, same hairstyle, same facial structure, same age and skin tone in every scene';
const characterAnchor = characterAnchorRaw || defaultAnchor;
const characterNegativePrompt = String(
  metadata.characterNegativePrompt ||
  'different person, identity change, face swap, deformed face, extra limbs, extra fingers, bad anatomy, blurry, low quality, watermark, text'
).trim();

const clipCount = Math.min(Math.max(toInt(metadata.clipCount, 8), 4), 12);
const clipDuration = Math.min(Math.max(toInt(metadata.clipDuration, 6), 4), 10);

const ratioInput = String(metadata.aspectRatio || payload.aspectRatio || '16:9').trim();
const ratioMap = {
  '16:9': { outputWidth: 1280, outputHeight: 720, genWidth: 768, genHeight: 432 },
  '9:16': { outputWidth: 720, outputHeight: 1280, genWidth: 432, genHeight: 768 },
  '1:1': { outputWidth: 1080, outputHeight: 1080, genWidth: 640, genHeight: 640 }
};
const aspectRatio = ratioMap[ratioInput] ? ratioInput : '16:9';
const ratioPreset = ratioMap[aspectRatio];

const comfyApiUrl = String(payload.comfyApiUrl || metadata.comfyApiUrl || '').trim().replace(/\/$/, '');
const comfyApiKey = String(payload.comfyApiKey || metadata.comfyApiKey || '').trim();
const comfyWorkflowFile = String(payload.comfyWorkflowFile || metadata.comfyWorkflowFile || '').trim();

const jobDir = `/root/.n8n-files/vidgen_${jobId}`;
const publicDir = `/var/www/vidgen-tmp/${jobId}`;
const publicBaseUrl = `https://automation.maksitech.id/vidgen-tmp/${jobId}`;

return [{ json: {
  jobId,
  uid: payload.uid || '',
  title: payload.title || 'Video tanpa judul',
  prompt: payload.prompt,
  source: payload.source || 'dashboard',
  category: payload.category || 'Umum',
  scheduledTime: normalizedScheduledTime,
  scheduledUploadAtIso,
  callbackUrl: payload.callbackUrl || '',
  callbackSecret: payload.callbackSecret || '',
  huggingfaceToken: payload.huggingfaceToken || '',
  comfyApiUrl,
  comfyApiKey,
  comfyWorkflowFile,
  appBaseUrl: payload.appBaseUrl || 'https://automation.maksitech.id',
  ollamaBaseUrl: (metadata.ollamaBaseUrl || payload.ollamaBaseUrl || 'http://127.0.0.1:11434').replace(/\/$/, ''),
  ollamaModel: metadata.ollamaModel || payload.ollamaModel || 'qwen2.5:7b-instruct',
  metadata,
  platforms,
  platformsStr: platforms.join(','),
  ttsVoice: metadata.ttsVoice || 'id-ID-ArdiNeural',
  style: metadata.style || 'cinematic documentary, high detail, dramatic lighting',
  mood: metadata.mood || 'informatif dan menarik',
  clipCount,
  clipDuration,
  aspectRatio,
  outputWidth: ratioPreset.outputWidth,
  outputHeight: ratioPreset.outputHeight,
  genWidth: ratioPreset.genWidth,
  genHeight: ratioPreset.genHeight,
  youtubeCategory: metadata.youtubeCategory || '27',
  seriesId,
  episodeNumber,
  characterName,
  characterAnchor,
  characterNegativePrompt,
  characterRefImageUrl,
  characterSeed,
  consistencyStrength: Math.max(Math.min(Number(metadata.consistencyStrength ?? 0.8), 1), 0),
  jobDir,
  narasiPath: `${jobDir}/narasi.mp3`,
  narasiTxtPath: `${jobDir}/narasi.txt`,
  clipsDir: `${jobDir}/clips`,
  filelistPath: `${jobDir}/filelist.txt`,
  rawVideoPath: `${jobDir}/raw.mp4`,
  finalVideoPath: `${jobDir}/final.mp4`,
  shortVideoPath: `${jobDir}/short.mp4`,
  thumbPath: `${jobDir}/thumb.jpg`,
  publicDir,
  publicBaseUrl,
  finalVideoUrl: `${publicBaseUrl}/final.mp4`,
  shortVideoUrl: `${publicBaseUrl}/short.mp4`,
  thumbUrl: `${publicBaseUrl}/thumb.jpg`,
  callbackHeaders: {
    'Content-Type': 'application/json',
    'x-vidgen-callback-secret': payload.callbackSecret || ''
  }
}}];

const resp = $input.first().json;
const raw = resp?.response || resp?.message?.content || '';
const prev = $('Normalize Request').first().json;

const HOOK_WORDS = ['TERBONGKAR', 'TERNYATA', 'FAKTA MENGEJUTKAN', 'WAJIB TAHU', 'JANGAN LEWATKAN'];
const MAX_TITLE_LEN = 90;

const toHookTitle = (candidate, fallback) => {
  const base = String(candidate || fallback || 'Video Menarik')
    .replace(/\s+/g, ' ')
    .trim();

  if (!base) return 'FAKTA MENGEJUTKAN: Hal Penting yang Wajib Kamu Tahu';

  const hasHook = /(terbongkar|ternyata|fakta|rahasia|jangan lewatkan|wajib tahu|mengubah cara pandang)/i.test(base);
  if (hasHook) return base.slice(0, MAX_TITLE_LEN);

  const hash = base.split('').reduce((acc, ch) => acc + ch.charCodeAt(0), 0);
  const hook = HOOK_WORDS[Math.abs(hash) % HOOK_WORDS.length];
  return (hook + ': ' + base).slice(0, MAX_TITLE_LEN);
};

let filtered = String(raw || '')
  .replace(/A[Ii]/g, 'Kami')
  .replace(/Artificial Intelligence/gi, 'Teknologi Canggih')
  .replace(/Robot/gi, 'Sistem');

let parsed;
try {
  const match = filtered.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : filtered);
} catch (e) {
  console.error('[Parse Ollama] Gagal parse JSON:', e.message);
  parsed = {
    narasi: 'Konten informatif mendalam tentang: ' + prev.prompt,
    video_prompts: Array(prev.clipCount || 8).fill('Photorealistic cinematic scene, detailed environment, clear subject action, dynamic camera movement, volumetric lighting, no text, no logo, no watermark'),
    judul: [String(prev.title || '') + ' - Fakta Lengkap'],
    judul_tiktok: String(prev.title || '').substring(0, 100),
    caption_facebook: String(prev.title || '') + ' - konten edukasi berkualitas. Bagikan ke temanmu!',
    deskripsi: 'Video tentang ' + prev.title + '. Subscribe untuk konten berkualitas! #edukasi #Indonesia',
    tags: ['edukasi', 'fakta', 'viral', 'indonesia', 'trending', 'youtube'],
    thumbnail_prompt: 'High contrast YouTube thumbnail about ' + prev.title + ', emotional expression, bold composition, 16:9',
    character_anchor: prev.characterAnchor,
    negative_prompt: prev.characterNegativePrompt
  };
}

const clipCount = Math.max(1, Number(prev.clipCount || 8));
const anchor = String(parsed.character_anchor || prev.characterAnchor || '').trim();
const negative = String(parsed.negative_prompt || prev.characterNegativePrompt || '').trim();

const sourcePrompts = Array.isArray(parsed.video_prompts)
  ? parsed.video_prompts.map((item) => String(item || '').trim()).filter(Boolean)
  : [];

const basePrompts = Array.from({ length: clipCount }, (_, index) => {
  const fromModel = sourcePrompts[index];
  if (fromModel) {
    return fromModel;
  }
  return 'Photorealistic cinematic scene ' + (index + 1) + ', clear action, rich environment details, balanced composition, dynamic camera movement, controlled lighting, no text, no logo, no watermark';
});

const videoPrompts = basePrompts.map((scenePrompt, index) => {
  const cleanScene = String(scenePrompt || '').trim() || ('Cinematic scene ' + (index + 1));
  const detailBoost = [
    cleanScene,
    'Include subject, action, environment depth, camera angle, lens feel, and lighting direction.',
    'Maintain continuity across clips and avoid generic framing.',
    'Style: ' + (prev.style || 'cinematic documentary') + '. Mood: ' + (prev.mood || 'informatif dan menarik') + '.',
    'No text overlay, no logo, no watermark.'
  ];
  if (anchor) detailBoost.push('Character anchor: ' + anchor + '. Keep exactly the same person identity and face.');
  if (negative) detailBoost.push('Negative prompt: ' + negative + '.');
  return detailBoost.join(' ').replace(/\s+/g, ' ').trim();
});

const rawTitle = Array.isArray(parsed.judul) ? parsed.judul[0] : (parsed.judul || prev.title);
const judulHook = toHookTitle(rawTitle, prev.title);

const tags = (Array.isArray(parsed.tags) ? parsed.tags : [])
  .map((t) => String(t || '').trim())
  .filter((t) => t && !/shorts?/i.test(t))
  .slice(0, 20);

return [{ json: {
  ...prev,
  narasi: parsed.narasi || '',
  video_prompts: videoPrompts,
  judul: judulHook,
  judul_tiktok: (parsed.judul_tiktok || rawTitle || prev.title || '').substring(0, 100),
  caption_facebook: parsed.caption_facebook || parsed.deskripsi || prev.title,
  deskripsi: parsed.deskripsi || '',
  tags,
  thumbnail_prompt: parsed.thumbnail_prompt || ('High contrast YouTube thumbnail about ' + prev.title + ', emotional expression, bold composition, 16:9'),
  characterAnchor: anchor || prev.characterAnchor,
  characterNegativePrompt: negative || prev.characterNegativePrompt,
  ollama_ok: true
}}];

const prev = $input.first().json;
const asB64 = (value) => Buffer.from(String(value || ''), 'utf-8').toString('base64');

const narasiB64 = asB64(prev.narasi || '');
const promptsB64 = asB64(JSON.stringify(prev.video_prompts || []));
const characterAnchorB64 = asB64(prev.characterAnchor || '');
const negativePromptB64 = asB64(prev.characterNegativePrompt || '');

return [{ json: {
  ...prev,
  narasiB64,
  promptsB64,
  characterAnchorB64,
  negativePromptB64
} }];

const stdout = $input.first().json.stdout || '';
const prev = $('Encode Base64').first().json;

const ttsOk = stdout.includes('TTS_OK');
const audioPath = stdout.match(/AUDIO_PATH:(.+)/)?.[1]?.trim() || prev.narasiPath;
const audioDuration = parseFloat(stdout.match(/AUDIO_DURATION:([\d.]+)/)?.[1] || '0');

if (!ttsOk) {
  console.error('[TTS] Gagal:', $input.first().json.stderr || stdout);
}

return [{ json: {
  ...prev,
  audio_ok: ttsOk,
  audio_path: audioPath,
  audio_duration: audioDuration
}}];

const stdout = $input.first().json.stdout || '';
const prev = $('Cek TTS').first().json;

const ffmpegOk = stdout.includes('FFMPEG_OK');
const finalDur = parseFloat(stdout.match(/FINAL_DURATION:([\d.]+)/)?.[1] || '0');
const finalSize = stdout.match(/FINAL_SIZE:(.+)/)?.[1]?.trim() || 'unknown';
const mins = Math.floor(finalDur / 60);
const secs = Math.floor(finalDur % 60);

if (!ffmpegOk) {
  console.error('[FFmpeg] Gagal:', $input.first().json.stderr || stdout);
  throw new Error('[FFmpeg] Assembly video gagal. Cek log Execute Command.');
}

return [{ json: {
  ...prev,
  ffmpeg_ok: ffmpegOk,
  final_duration: finalDur,
  final_duration_str: `${mins}m ${secs}s`,
  final_size: finalSize
}}];

const err = $input.first().json;
const safeNode = (name) => {
  try {
    return $(name).first().json;
  } catch (e) {
    return {};
  }
};
const normalized = safeNode('Normalize Request');
const parsedFfmpeg = safeNode('Parse Hasil FFmpeg');
const lastNode = String(err.error?.node?.name || err.execution?.lastNodeExecuted || err.lastNodeExecuted || '').trim();
const errorMessage = String(err.error?.message || err.message || 'Unknown error').trim();
const jobId = String(normalized.jobId || parsedFfmpeg.jobId || err.jobId || '').trim();
const callbackUrl = String(normalized.callbackUrl || parsedFfmpeg.callbackUrl || '').trim();
const callbackHeaders = normalized.callbackHeaders || parsedFfmpeg.callbackHeaders || { 'Content-Type': 'application/json' };
return [{ json: {
  jobId,
  callbackUrl,
  callbackHeaders,
  error: errorMessage,
  executionId: err.execution?.id || '',
  currentNode: lastNode || 'Unknown Node',
  currentStage: 'workflow_failed',
  stageLabel: lastNode ? `Gagal di node ${lastNode}` : 'Workflow gagal',
  message: lastNode ? `Workflow gagal di node ${lastNode}.` : 'Workflow gagal saat diproses.'
} }];

const stdout = $input.first().json.stdout || '';
const stderr = $input.first().json.stderr || '';
const prev = $('Parse Hasil FFmpeg').first().json;

let results = {};
let parseError = '';
try {
  const match = stdout.match(/UPLOAD_RESULTS:(\{[\s\S]*\})/);
  if (match) {
    results = JSON.parse(match[1]);
  } else {
    parseError = 'Marker UPLOAD_RESULTS tidak ditemukan di stdout.';
  }
} catch (e) {
  parseError = e.message;
  console.error('[Upload Parse] Error:', e.message, stdout);
}

const youtubeOk = results.youtube?.ok || false;
const youtubeUrl = results.youtube?.url || '';
const uploadSummary = [];
if (youtubeUrl) uploadSummary.push(`YouTube: ${youtubeUrl}`);

const credsState = {
  clientIdLoaded: /YOUTUBE_CLIENT_ID loaded:\s*yes/i.test(stdout),
  clientSecretLoaded: /YOUTUBE_CLIENT_SECRET loaded:\s*yes/i.test(stdout),
  refreshTokenLoaded: /YOUTUBE_REFRESH_TOKEN loaded:\s*yes/i.test(stdout),
};

if (!youtubeOk) {
  const message = [
    results.youtube?.error,
    parseError,
    stderr,
    stdout ? stdout.slice(0, 1500) : '',
  ].filter(Boolean).join(' | ');
  throw new Error(`Upload YouTube gagal. creds=${JSON.stringify(credsState)}. ${message || 'Tanpa detail.'}`.slice(0, 1800));
}

return [{ json: {
  ...prev,
  youtubeUrl,
  uploadResults: results,
  uploadSummary,
  uploadStdout: stdout,
  uploadStderr: stderr,
  uploadCredsState: credsState
}}];
